[ExtensionOf(classStr(SalesInvoiceJournalCreate))]
internal final class ETGSalesInvoiceJournalCreate_Extension
{  
}

Method.Source:
/// <summary>
/// This method initializes field TERMO Value Usage based on Line Amount 
/// </summary>
/// <param name = "_salesParmLine">SalesParmLine _salesParmLine</param>
protected void initInvoiceLineFromSourceLine(SalesParmLine _salesParmLine)
{
    next initInvoiceLineFromSourceLine(_salesParmLine);
    if(VendParameters::find().ETGEnableTermoNumberFeature == NoYes::Yes)
    {
        custInvoiceTrans.ETGTermoValueUsageReal = _salesParmLine.LineAmount;
    }

    if(SalesParameters::find().ETGEnableCylinderTracking)
    {
        SalesLine    salesLineLoc           = _salesParmLine.salesLine();
        custInvoiceTrans.ETGConnectionType  = salesLineLoc.ETGConnectionType;
        custInvoiceTrans.ETGDepositAmount   = salesLineLoc.ETGDepositAmount;
        custInvoiceTrans.ETGDepositRate     = salesLineLoc.ETGDepositRate;
        custInvoiceTrans.ETGFilledOrEmpty   = salesLineLoc.ETGFilledOrEmpty;
    }
 }
